sql:
SELECT time, power
FROM seismic_data
WHERE data_id = 1;

SELECT azimuth, MAX(power) AS max_power
FROM seismic_data
GROUP BY azimuth;

SELECT noise_level, data_integrity
FROM data_quality
WHERE data_id = 1;

SELECT time, data_id
FROM seismic_data
WHERE noise > (SELECT AVG(noise) FROM seismic_data);

SELECT * 
FROM seismic_data 
WHERE noise > 10;

SELECT data_id, tag_name
FROM data_tags
WHERE tag_name = 'volcanic activity';

SELECT processing_id, processing_date, processing_result 
FROM data_processing 
WHERE data_id = 1 AND processing_type = 'filtering';

SELECT sd.data_id, ds.source_name
FROM seismic_data sd
JOIN data_sources ds ON sd.data_source_id = ds.source_id;

SELECT AVG(power)
FROM seismic_data
WHERE valid = 1;

SELECT *
FROM seismic_data
WHERE valid = 1 AND frequency > 2.0 AND slowness < 0.5;

SELECT s.*, l.license_type, l.license_terms, l.license_date
FROM seismic_data s
LEFT JOIN data_licenses l ON s.data_id = l.data_id;

external_knowledge:
- 'Whispers of the earth' metaphorically refer to seismic data sources;
- 'Murmurs' symbolize the noise levels in the seismic waves;
- 'Gentle breeze' is a metaphor for a noise level threshold of 50;
- 'Silent language of the Love waves' refers to seismic waves of the 'Love' type;
- 'Filtering out the inaudible whispers' implies only valid data entries are considered.

sql:
SELECT citation_id 
FROM data_citations 
WHERE citation_type = 'conference';

SELECT validation_id, validation_date
FROM data_validation
WHERE status = 'valid';

external_knowledge:
- 'Highest clarity' refers to the highest data quality score;
- 'Originates from the depths of an earthquake' refers to the tag name 'earthquake';
- 'Recorded in scholarly journals' refers to the citation type 'journal';
- 'Cornerstone in the lineage of data' refers to the relationship type 'parent';
- 'Flawless signal without any murkiness' refers to a noise level of 0;
- 'Strength that dwarfs the rest' means a signal strength greater than 10,000.

- Powerful: Refers to seismic waves with power greater than 100.0;
- Quite clean: Implies noise levels are likely under 2, indicating a low noise environment;
- Point in a specific direction: The sine of the azimuth (direction of the wave) is greater than 0.9, suggesting the waves are directed within certain angles, likely northwards;
- Sorted by their quality in descending order: Indicates ordering by `data_quality_score` from highest to lowest.
